  ('cpa-moex-00211', 'cpa', 'cpa-moex-112-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '董事 乙 B股份有限公司', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:01+00:00", "source_pdf_sha1": "7e6267f2c8a0", "answer_pdf_sha1": "18299ad61349", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
